#!/usr/bin/env python3
import json
import csv
import ipaddress
import sys

def ip_in_cidr(ip_str, cidr_str):
    """Check if an IP address is within a CIDR range."""
    try:
        ip = ipaddress.ip_address(ip_str)
        network = ipaddress.ip_network(cidr_str, strict=False)
        return ip in network
    except ValueError:
        return False

def port_in_range(port, port_spec):
    """Check if a port matches a port specification (single port or range)."""
    try:
        port = int(port)
        if '-' in str(port_spec):
            # Port range like "1024-65535"
            start, end = map(int, str(port_spec).split('-'))
            return start <= port <= end
        else:
            # Single port
            return port == int(port_spec)
    except (ValueError, AttributeError):
        return False

def find_matching_rule(source_ip, dest_port, rules):
    """Find the most specific matching rule for a given source IP and destination port.

    Returns the matching rule or None if no rule matches.
    Rules are sorted by CIDR prefix length (most specific first).
    """
    matching_rules = []

    for rule in rules:
        source_cidr = rule.get('source_cidr', '')
        allowed_ports = rule.get('allowed_ports', [])

        # Check if IP is in the CIDR range
        if ip_in_cidr(source_ip, source_cidr):
            # Check if port matches any allowed port/range
            for port_spec in allowed_ports:
                if port_in_range(dest_port, port_spec):
                    # Calculate prefix length for sorting (more specific = longer prefix)
                    try:
                        network = ipaddress.ip_network(source_cidr, strict=False)
                        prefix_len = network.prefixlen
                        matching_rules.append((prefix_len, rule))
                    except ValueError:
                        pass
                    break  # Found a matching port, no need to check other ports for this rule

    if matching_rules:
        # Sort by prefix length (descending) - most specific first
        matching_rules.sort(key=lambda x: x[0], reverse=True)
        return matching_rules[0][1]

    return None

def main():
    # Load firewall rules
    try:
        with open('/home/user/audit/firewall_rules.json', 'r') as f:
            data = json.load(f)
            rules = data.get('rules', [])
    except (FileNotFoundError, json.JSONDecodeError) as e:
        print(f"Error loading firewall rules: {e}", file=sys.stderr)
        sys.exit(1)

    # Load active connections
    try:
        with open('/home/user/audit/connections.csv', 'r') as f:
            reader = csv.DictReader(f)
            connections = list(reader)
    except FileNotFoundError as e:
        print(f"Error loading connections: {e}", file=sys.stderr)
        sys.exit(1)

    # Check each connection against firewall rules
    for conn in connections:
        source_ip = conn.get('source_ip', '').strip()
        dest_port = conn.get('dest_port', '').strip()

        if not source_ip or not dest_port:
            continue

        # Find matching rule
        matching_rule = find_matching_rule(source_ip, dest_port, rules)

        if matching_rule is None:
            # No rule allows this connection - it's blocked by default-deny
            # Find the most specific CIDR that contains this IP for reporting
            containing_cidrs = []
            for rule in rules:
                source_cidr = rule.get('source_cidr', '')
                if ip_in_cidr(source_ip, source_cidr):
                    try:
                        network = ipaddress.ip_network(source_cidr, strict=False)
                        containing_cidrs.append((network.prefixlen, source_cidr))
                    except ValueError:
                        pass

            if containing_cidrs:
                # Report with the most specific CIDR
                containing_cidrs.sort(key=lambda x: x[0], reverse=True)
                cidr = containing_cidrs[0][1]
            else:
                # No CIDR contains this IP, report with a generic message
                cidr = "any"

            print(f"BLOCKED: {source_ip}:{dest_port} not allowed from {cidr}")

if __name__ == '__main__':
    main()
